xf:group.script:
/**
 * //property handling
 * $w.log("id:" + options.id);
 * $w.log("style:" + options.style);
 * $w.log("class:" + options.class);
 * $w.log("ref:" + options.ref);
 *
 * //event trigger
*/
// 초기 수행함수 
this.initFlowSttusLabel = function() {
	this.setStyle("background", options.background || "#FFFFFF");

	var labelBackUrl = "url(#" + radialGradient.getID() + ")";
	document.getElementById(labelTitleBack.getID()).setAttribute("fill", labelBackUrl);

	var titleId = document.getElementById(labelTextTop.getID());
	var allText = document.getElementsByTagName("text");
	var textClass = document.querySelectorAll(".label-text-wrap");

	var titleTextTop = document.getElementById(labelTitleTextTop.getID());
	if (options.topTitle && options.topTitle != "") {
		titleTextTop.innerHTML = options.topTitle;
	}
	if (options.topX && options.topX != "") {
		titleTextTop.setAttribute("x", options.topX);
	}
	if (options.topY && options.topY != "") {
		titleTextTop.setAttribute("y", options.topY);
	}

	var titleTextBottom = document.getElementById(labelTitleTextBottom.getID());
	if (options.bottomTitle && options.bottomTitle != "") {
		titleTextBottom.innerHTML = options.bottomTitle;
	}
	if (options.bottomX && options.bottomX != "") {
		titleTextBottom.setAttribute("x", options.bottomX);
	}
	if (options.bottomY && options.bottomY != "") {
		titleTextBottom.setAttribute("y", options.bottomY);
	}

	var text = document.getElementById(labelTextTop.getID());
	if (options.text && options.text != "") {
		text.innerHTML = options.text;
	}
	if (options.textX && options.textX != "") {
		text.setAttribute("x", options.textX);
	}
	if (options.textY && options.textY != "") {
		text.setAttribute("y", options.textY);
	}
};

this.setLabelTitleText = function(topTitle, topX, topY, bottomTitle, bottomX, bottomY) {
	var titleTextTop = document.getElementById(labelTitleTextTop.getID());
	if (topTitle && topTitle != "") {
		titleTextTop.innerHTML = topTitle;
	}
	if (topX && topX != "") {
		titleTextTop.setAttribute("x", topX);
	}
	if (topY && topY != "") {
		titleTextTop.setAttribute("y", topY);
	}

	var titleTextBottom = document.getElementById(labelTitleTextBottom.getID());
	if (bottomTitle && bottomTitle != "") {
		titleTextBottom.innerHTML = bottomTitle;
	}
	if (bottomX && bottomX != "") {
		titleTextBottom.setAttribute("x", bottomX);
	}
	if (bottomY && bottomY != "") {
		titleTextBottom.setAttribute("y", bottomY);
	}
};

this.setLabelText = function(titleTop, topX, topY, titleBottom, bottomX, bottomY) {
	var textTop = document.getElementById(labelTextTop.getID());
	var textBottom = document.getElementById(labelTextBottom.getID());

	if (titleTop && titleTop != "") {
		textTop.innerHTML = titleTop;
	}
	if (topX && topX != "") {
		textTop.setAttribute("x", topX);
	}
	if (topY && topY != "") {
		textTop.setAttribute("y", topY);
	}
	if (titleBottom && titleBottom != "") {
		textBottom.innerHTML = titleBottom;
		textTop.setAttribute("y", (Number(topY)-40).toString());
		textBottom.setAttribute("y", (Number(topY)+20).toString());
		textBottom.setAttribute("x", topX);
	} else {
		textBottom.innerHTML = "";
	}
};

this.cleanLabelTitleProcess = function() {
	var labelBackUrl = "url(#" + radialGradient.getID() + ")";
	var titleTextTop = document.getElementById(labelTitleTextTop.getID());
	var titleTextBottom = document.getElementById(labelTitleTextBottom.getID());

	//title 초기화
	document.getElementById(labelTitleBack.getID()).setAttribute("fill", labelBackUrl);
	titleTextTop.classList.remove("title-animate-blinking-50");
	titleTextTop.classList.remove("title-color-gray");
	titleTextBottom.classList.remove("title-animate-blinking-50");
	titleTextBottom.classList.remove("title-color-gray");
}

//param {bChange : 변경 여부, bData : 데이터 여부, fillColor : 타이틀 색상}
this.setLabelTitleProcess = function(bChange, bData, fillColor) {
	if (!fillColor) fillColor = "#8E8E8E";
	var labelBackUrl = "url(#" + radialGradient.getID() + ")";
	var titleTextTop = document.getElementById(labelTitleTextTop.getID());
	var titleTextBottom = document.getElementById(labelTitleTextBottom.getID());

	//title 설정
	if(!bChange) {
		titleTextTop.classList.add("title-color-gray");
		titleTextBottom.classList.add("title-color-gray");
		document.getElementById(labelTitleBack.getID()).setAttribute("fill", fillColor);
	}
	if(bData) {
		if(bChange) {
			titleTextTop.classList.add("title-animate-blinking-50");
			titleTextBottom.classList.add("title-animate-blinking-50");
		}
	}
};

// 초기 실행함수 수행
this.initFlowSttusLabel();
